#!/bin/bash

echo "============================================"
echo "  DocZ+ Deployment Script"
echo "============================================"
echo ""

# Colors
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
RED='\033[0;31m'
NC='\033[0m'

# Check Node.js
if ! command -v node &> /dev/null; then
    echo -e "${RED}Error: Node.js is not installed${NC}"
    exit 1
fi

echo -e "${GREEN}Step 1: Installing Blockchain dependencies...${NC}"
cd blockchain
npm install
if [ $? -ne 0 ]; then
    echo -e "${RED}Failed to install blockchain dependencies${NC}"
    exit 1
fi
echo -e "${GREEN}Blockchain dependencies installed!${NC}"
echo ""

echo -e "${GREEN}Step 2: Compiling Smart Contracts...${NC}"
npm run compile
if [ $? -ne 0 ]; then
    echo -e "${RED}Failed to compile contracts${NC}"
    exit 1
fi
echo -e "${GREEN}Contracts compiled successfully!${NC}"
echo ""

echo -e "${YELLOW}Step 3: Deploy to Polygon Amoy Testnet${NC}"
echo "Make sure you have:"
echo "  - FUNDED wallet on Polygon Amoy"
echo "  - POLYGONSCAN_API_KEY in .env"
echo ""
read -p "Deploy now? (y/n): " -n 1 -r
echo ""
if [[ $REPLY =~ ^[Yy]$ ]]; then
    npm run deploy:amoy
    if [ $? -eq 0 ]; then
        echo ""
        echo -e "${GREEN}Contract deployed! Copy the address to Vercel env vars${NC}"
    fi
fi
echo ""

echo -e "${GREEN}Step 4: Installing API dependencies...${NC}"
cd ../api
npm install
echo -e "${GREEN}API dependencies installed!${NC}"
echo ""

echo -e "${GREEN}Step 5: Installing Frontend dependencies...${NC}"
cd ../client
npm install
echo -e "${GREEN}Frontend dependencies installed!${NC}"
echo ""

echo "============================================"
echo -e "${GREEN}  Setup Complete!${NC}"
echo "============================================"
echo ""
echo "Next steps:"
echo "1. Deploy contract: cd blockchain && npm run deploy:amoy"
echo "2. Copy contract address to Vercel environment variables"
echo "3. Create MongoDB Atlas account and get connection string"
echo "4. Add all environment variables to Vercel"
echo "5. Deploy: vercel --prod"
echo ""
echo "For local development:"
echo "  Terminal 1: cd api && npm run dev"
echo "  Terminal 2: cd client && npm run dev"
echo ""
